Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create insert statement
  auto insert_stmt = transpilation::to_insert_or_write<T, sqlgen::dynamic::Insert>();
  insert_stmt.table = table_name;

  // Convert records to dynamic values
  std::vector<std::vector<sqlgen::dynamic::Value>> values;
  for (const auto& record : records) {
    std::vector<sqlgen::dynamic::Value> row;
    // Convert each field to dynamic value
    for (const auto& field : rfl::to_view(record)) {
      row.emplace_back(transpilation::to_value(field));
    }
    values.push_back(std::move(row));
  }

  // Execute insert
  auto result = conn->insert(insert_stmt, values.begin(), values.end());
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::optional<std::string>& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create update statement
  auto update_stmt = transpilation::to_insert_or_write<T, sqlgen::dynamic::Update>();
  update_stmt.table = table_name;

  // Set the column value
  auto set_clause = sqlgen::dynamic::Set{
      .col = col_name,
      .to = transpilation::to_value(new_value)
  };
  update_stmt.sets = {set_clause};

  // Add where clause for primary key
  auto where_cond = sqlgen::dynamic::Condition{
      .op = sqlgen::dynamic::Condition::Equal,
      .left = sqlgen::dynamic::Column{.name = "id"},
      .right = sqlgen::dynamic::Value{record_id}
  };
  update_stmt.where = where_cond;

  // Execute update
  auto result = conn->update(update_stmt);
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create delete statement
  auto delete_stmt = sqlgen::dynamic::DeleteFrom{
      .table = table_name,
      .where = sqlgen::dynamic::Condition{
          .op = sqlgen::dynamic::Condition::Equal,
          .left = sqlgen::dynamic::Column{.name = "id"},
          .right = sqlgen::dynamic::Value{record_id}
      }
  };

  // Execute delete
  auto result = conn->delete_from(delete_stmt);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to the EAS database
2. **Error Handling**: Proper error checking using the Result type pattern shown in the reference materials
3. **Dynamic SQL Generation**: Uses `transpilation::to_insert_or_write()` to create appropriate SQL statements
4. **Type Safety**: Leverages sqlgen's type system for proper value conversion
5. **Primary Key Handling**: Assumes all tables have an "id" column as primary key for the WHERE clause
6. **Batch Operations**: Supports batch insertion through vector of records

**Note**: The implementation assumes that all tables have a primary key column named "id". If the actual primary key column names differ, the `where` clause in `modify_eas_records_by_id` and `delete_eas_records_by_id` would need to be adjusted accordingly.

