#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

    // Chain operations using and_then for error handling
    return conn_result
        .and_then(sqlgen::drop<Product> | sqlgen::if_exists)  // Drop table if exists
        .and_then([](auto conn) { 
            return sqlgen::write(conn, std::vector<Product>{});  // Create table
        })
        .and_then(sqlgen::begin_transaction)  // Begin transaction
        .and_then([&products](auto conn) { 
            return sqlgen::write(conn, products);  // Batch insert products
        })
        .and_then(sqlgen::commit)  // Commit transaction
        .is_ok();  // Return true if all operations succeeded
}

}  // namespace batch_insert_products
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Drop**: Uses `sqlgen::drop<Product> | sqlgen::if_exists` to safely drop the table if it exists
3. **Table Creation**: Creates empty table by writing an empty vector `std::vector<Product>{}`
4. **Transaction Management**: Uses `sqlgen::begin_transaction` and `sqlgen::commit` for atomic operations
5. **Batch Insertion**: Uses `sqlgen::write(conn, products)` for efficient batch insertion
6. **Error Handling**: Chains operations with `and_then` and checks final success with `is_ok()`
7. **Return Value**: Returns `true` only if all operations complete successfully

The implementation follows the sqlgen library patterns demonstrated in the reference materials, using the functional composition approach with `and_then` for proper error propagation and transaction safety.

