 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create tables
  create_table<Course>(conn).value();
  create_table<Enrollment>(conn).value();

  // 3. Build and execute the query
  auto query = select_from<Course, "c">(
      "title"_c,
      count("enrollment_id"_e).as<"student_count">(),
      avg("grade"_e).as<"avg_grade">()
    ) | left_join<Enrollment, "e">("course_id"_c == "course_id"_e)
      | group_by("course_id"_c, "title"_c)
      | to<std::vector<CourseStatsView>>;

  // 4. Convert results to CourseStats and return
  auto results = query(conn).value();
  std::vector<CourseStats> stats;
  for (const auto& result : results) {
    stats.push_back(CourseStats{
        .title = result.title,
        .student_count = result.student_count,
        .avg_grade = result.avg_grade
    });
  }
  return stats;
}

}  // namespace query_course_enrollment_stats
