  // Get column definitions for the new columns
  // We need to find the new columns in the new_create_table.columns
  // that are not present in the old_create_table.columns
  std::vector<sqlgen::dynamic::Column> old_columns = old_create_table.columns;
  std::vector<sqlgen::dynamic::Column> new_columns = new_create_table.columns;

  // Find the new columns (phone_number and is_active)
  std::vector<sqlgen::dynamic::Column> new_cols;
  for (const auto& col : new_columns) {
    bool is_new_column = true;
    for (const auto& old_col : old_columns) {
      if (col.name == old_col.name) {
        is_new_column = false;
        break;
      }
    }
    if (is_new_column) {
      new_cols.push_back(col);
    }
  }

  // Generate ALTER TABLE statements for each new column
  std::vector<std::string> alter_statements;
  for (const auto& col : new_cols) {
    std::string sql = "ALTER TABLE " + table_name + " ADD COLUMN " + col.name + " ";

    // Convert column type to SQL representation
    if (col.type.visit([](const auto& t) {
      using T = std::remove_cvref_t<decltype(t)>;
      if constexpr (std::is_same_v<T, sqlgen::dynamic::types::Boolean>) {
        return "BOOLEAN DEFAULT TRUE";
      } else if constexpr (std::is_same_v<T, sqlgen::dynamic::types::Text>) {
        return "VARCHAR(255)";
      }
      return "";
    }));

    alter_statements.push_back(sql);
  }

