namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Begin transaction for atomicity
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    bool success = true;

    // Iterate through each document ID and perform the update
    for (auto id : ids) {
        // Create the update statement using sqlgen::update
        auto update_stmt = sqlgen::update<Document>(
            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
        ) | sqlgen::where("doc_id"_c == id);

        // Execute the update
        auto result = update_stmt(*conn);
        if (!result) {
            success = false;
            break;
        }
    }

    // Commit the transaction if all updates succeeded
    if (success) {
        auto commit_result = conn->commit();
        if (!commit_result) {
            success = false;
        }
    } else {
        // Rollback if any update failed
        conn->rollback();
    }

    return success;
}

}  // namespace soft_delete_records
