struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Read from_account balance
    auto from_account_result = (sqlgen::read<std::vector<Account>> | where("account_id"_c == from_account_id))(conn);
    if (!from_account_result) {
      conn->rollback();
      return false;
    }

    auto from_account = *from_account_result;
    if (from_account.empty() || from_account[0].balance < amount) {
      conn->rollback();
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from_result = (sqlgen::update<Account>(set("balance"_c = "balance"_c - amount)) 
                             | where("account_id"_c == from_account_id))(conn);
    if (!update_from_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to_result = (sqlgen::update<Account>(set("balance"_c = "balance"_c + amount)) 
                           | where("account_id"_c == to_account_id))(conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
