  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Perform insert-or-replace operation using sqlgen::write with sqlgen::or_replace
  auto write_result = (sqlgen::write(items) | sqlgen::or_replace)(conn);
  if (!write_result) {
    return false;
  }

  // 3. Read back the items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false;
  }
  auto read_items = *read_result;

  // 4. Verify that the number of items matches and all items are present
  if (read_items.size() != items.size()) {
    return false;
  }

  // Create a map of item_id to Inventory for quick lookup
  std::unordered_map<int, Inventory> item_map;
  for (const auto& item : read_items) {
    item_map[item.item_id] = item;
  }

  // Verify each item exists and has correct values
  for (const auto& original_item : items) {
    auto found_it = item_map.find(original_item.item_id);
    if (found_it == item_map.end()) {
      return false;
    }

    const auto& verified_item = found_it->second;
    if (verified_item.name != original_item.name ||
        verified_item.quantity != original_item.quantity) {
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
