  EXPECT_DOUBLE_EQ(mouse.floor_price, 25.0);

  // Verify Keyboard data
  const auto& keyboard = results[2];
  EXPECT_EQ(keyboard.product_id, 3);
  EXPECT_DOUBLE_EQ(keyboard.abs_price, 150.75);
}

